import React, { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import Layout from '../../components/shared/Layout';
import axiosInstance from '../../utils/axiosInstance';

const Badge = ({ status }) => {
  const colors = { ACTIVE: '#22c55e', REQUESTED: '#3b82f6', AT_RISK: '#f59e0b', DEACTIVATED: '#ef4444', REJECTED: '#94a3b8' };
  const c = colors[status] || '#94a3b8';
  return <span style={{ padding: '3px 10px', borderRadius: 99, background: c + '20', color: c, fontWeight: 700, fontSize: 12 }}>{status}</span>;
};

export default function AdminAccounts() {
  const [accounts, setAccounts] = useState([]);
  const [filter, setFilter] = useState('ALL');

  const fetchAccounts = () => axiosInstance.get('/accounts').then(r => setAccounts(r.data.accounts || []));
  useEffect(() => { fetchAccounts(); }, []);

  const action = async (url, msg) => {
    try { await axiosInstance.patch(url); toast.success(msg); fetchAccounts(); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const statuses = ['ALL', 'REQUESTED', 'ACTIVE', 'AT_RISK', 'DEACTIVATED', 'REJECTED'];
  const filtered = filter === 'ALL' ? accounts : accounts.filter(a => a.status === filter);

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <h2 style={{ margin: '0 0 24px', color: '#1e293b' }}> Accounts</h2>
      </div>

      <div className="d-flex flex-wrap gap-2 mb-4">
        {statuses.map(s => (
          <button key={s} onClick={() => setFilter(s)}
            style={{ padding: '6px 14px', borderRadius: 99, border: 'none', cursor: 'pointer', fontWeight: 600, fontSize: 12,
              background: filter === s ? '#1e293b' : '#fff', color: filter === s ? '#fff' : '#64748b', boxShadow: '0 1px 4px rgba(0,0,0,0.08)' }}>
            {s}
          </button>
        ))}
      </div>

      <div style={{ background: '#fff', borderRadius: 12, overflow: 'hidden', boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
        <div className="table-responsive">
          <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: 800 }}>
            <thead>
              <tr style={{ background: '#f8fafc' }}>
                {['Account No.', 'Customer ID', 'Type', 'Balance', 'Status', 'Deactivation Type', 'AT RISK Since', 'Actions'].map(h => (
                  <th key={h} style={{ padding: '12px 16px', textAlign: 'left', fontSize: 12, fontWeight: 700, color: '#475569', borderBottom: '1px solid #e2e8f0' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map(a => (
                <tr key={a.accountNumber} style={{ borderBottom: '1px solid #f1f5f9' }}>
                  <td style={{ padding: '12px 16px', fontFamily: 'monospace', fontSize: 12, color: '#3b82f6' }}>{a.accountNumber}</td>
                  <td style={{ padding: '12px 16px', fontSize: 12, color: '#64748b' }}>{a.customerId}</td>
                  <td style={{ padding: '12px 16px', fontSize: 13 }}>{a.accountType}</td>
                  <td style={{ padding: '12px 16px', fontWeight: 600 }}>₹{a.balance?.toLocaleString('en-IN')}</td>
                  <td style={{ padding: '12px 16px' }}><Badge status={a.status} /></td>
                  <td style={{ padding: '12px 16px', fontSize: 12, color: '#94a3b8' }}>{a.deactivationType || '—'}</td>
                  <td style={{ padding: '12px 16px', fontSize: 12, color: '#f59e0b' }}>{a.atRiskSince ? new Date(a.atRiskSince).toLocaleDateString('en-IN') : '—'}</td>
                  <td style={{ padding: '12px 16px' }}>
                    <div className="d-flex flex-wrap gap-1">
                      {a.status === 'REQUESTED' && <>
                        <button onClick={() => action(`/accounts/${a.accountNumber}/approve`, 'Account approved!')} style={{ padding: '4px 10px', borderRadius: 6, border: 'none', background: '#22c55e', color: '#fff', fontWeight: 700, fontSize: 11, cursor: 'pointer' }}>Approve</button>
                        <button onClick={() => action(`/accounts/${a.accountNumber}/reject`, 'Account rejected')} style={{ padding: '4px 10px', borderRadius: 6, border: 'none', background: '#ef4444', color: '#fff', fontWeight: 700, fontSize: 11, cursor: 'pointer' }}>Reject</button>
                      </>}
                      {(a.status === 'ACTIVE' || a.status === 'AT_RISK') && (
                        <button onClick={() => action(`/accounts/${a.accountNumber}/deactivate`, 'Account deactivated')} style={{ padding: '4px 10px', borderRadius: 6, border: 'none', background: '#ef4444', color: '#fff', fontWeight: 700, fontSize: 11, cursor: 'pointer' }}>Deactivate</button>
                      )}
                      {a.status === 'DEACTIVATED' && (
                        <button onClick={() => action(`/accounts/${a.accountNumber}/activate`, 'Account activated!')} style={{ padding: '4px 10px', borderRadius: 6, border: 'none', background: '#22c55e', color: '#fff', fontWeight: 700, fontSize: 11, cursor: 'pointer' }}>Activate</button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && <tr><td colSpan={8} style={{ padding: 24, textAlign: 'center', color: '#94a3b8' }}>No accounts found</td></tr>}
            </tbody>
          </table>
        </div>
      </div>
    </Layout>
  );
}
